--- 战斗动作播放表演器
---@class LFightAniActor
local LFightAniActor = LxClass("LFightAniActor",nil)
----------------------------------------------------------------
-----------------------------------------------------------------
function LFightAniActor:LFightAniActor(battleUnit,obj)
	---@type LFightUnit
	self._battleUnit = battleUnit
	---@type LFightObject
	self._obj = obj

	self._endTime = 0

	self._isFreeze = false

	self._bWaitEnd = false

	self._ani = nil
end

------------------------------------------------------------------
function LFightAniActor:OnRun(time)
	self:UpdateFreeze()
	self:UpdateAni(time)
	self:CheckUpdate(time)
end


---播放动画 1,播完需要回到idle循环 2,不需要
-----------------------------------------------------------------
function LFightAniActor:PlayAni(ani,loop,aniTime,mixTime)
    local curTime = self._battleUnit:GetTime()
	self._ani = ani

	if LOG_INFO_ENABLED then
		--local id = self._obj:GetId()
		--print(string.format("id %s  play ani %s",id,ani))
	end

	aniTime = aniTime or 0
	self._needReset = false
	self._resetExecute = true
	if aniTime > 0 then
		self._endTime = curTime + aniTime
		self._needReset = true
		self._resetExecute = false
	end
	self._obj:PlayAni_Actor(ani,loop,mixTime)

	if not self._needReset then
		self._delayCheckTime = curTime + 0.2
	else
		self._delayCheckTime = nil
	end
end



-----------------------------------------------------------------

function LFightAniActor:UpdateAni(time)
	if self._resetExecute then
		return
	end

	if time < self._endTime then
		return
	end

	self._resetExecute = true

	self:ResetAni()
end

function LFightAniActor:ResetAni()
	local timeScale = self._isFreeze and 0 or 1
	self._obj:SetAniTimeScale_Actor(timeScale)
	if not self._isFreeze and self._needReset then
		self._obj:PlayIdleAni()
	end

end


function LFightAniActor:SetFreeze(isFreeze) --延迟冻结
	self._isFreeze = isFreeze
	self._freezeExecuted = false
end

function LFightAniActor:UpdateFreeze()
	if self._freezeExecuted then
		return
	end

	self._freezeExecuted = true

	self:ResetAni()
end

function LFightAniActor:CheckUpdate(time)
	if not self._delayCheckTime then
		return
	end

	if self._delayCheckTime < time then
		return
	end

	self._delayCheckTime = nil

	local timeScale = self._isFreeze and 0 or 1
	self._obj:SetAniTimeScale_Actor(timeScale)
end

function LFightAniActor:GetAniName()
	return self._ani
end

-----------------------------------------------------------------
function LFightAniActor:Destroy()
	self._obj = nil
	self._battleUnit = nil
end

return LFightAniActor